#include <stdlib.h>
#include<string.h>
#include<stdio.h>
int main (void)
{

    int i, j, a, b;
	scanf("%d %d",&a,&b);
	char string[a], temp;
    scanf("%s",string);

    for (i=0; i<a-1; i++)
    {
        for (j=i+1; j<a; j++)
        {
            if (string[i] > string[j])
            {
                temp = string[i];
                string[i] = string[j];
                string[j] = temp;
            }
        }
    }

    int ar[a];
    for(i=0;i<a;i++)
    	ar[i]=string[i]-'a'+1;

    int sum=ar[0];
    int flag = 1;
    int temp2 = ar[0];
    for(i=1; i<a;i++){
    	if(flag==b)
			break;
    	if(ar[i]-temp2>1){
    		sum+=ar[i];
			temp2=ar[i];
			flag++;
		}
	}

	if(flag!=b)
		printf("-1");
	else
		printf("%d",sum);

    return 0;
}

