fn solution(s: String, n: i32) -> i32 {
  let mut chars = s.trim().as_bytes().iter().cloned().map (|x| x - 96u8).collect::<Vec<u8>>();
  chars.sort();
  let mut iter = chars.iter().peekable();
  let mut not_found = false;
  let mut prev_char = *iter.next().unwrap() as i32;
  let mut sum = prev_char.clone() as i32;
  let mut m = n;
  loop {
    if m < 2 {
      break;
    }
    if iter.peek().is_none() {
      not_found = true;
      break;
    }

    let a = *iter.next().unwrap() as i32;
    if a - prev_char < 2 {
      continue;
    } 
    sum += a.clone() as i32;
    prev_char = a;
    m-=1;
  }
  if not_found {-1} else {sum}
}

fn main() {
  assert_eq!(29,solution(String::from("xyabd"),3));
  assert_eq!(34,solution(String::from("problem"),4));
  assert_eq!(-1,solution(String::from("ab"),2));
  assert_eq!(1,solution(String::from("abaabbaaabbb"),1));


  let mut r = String::new();
  std::io::stdin().read_line(&mut r).unwrap();
  let mut ns = r.split_whitespace().map(|x| x.parse::<i32>().unwrap());
  ns.next().unwrap();
  let n  = ns.next().unwrap();
  let mut s = String::new();
  std::io::stdin().read_line(&mut s).unwrap();
  println!("{}",solution(s,n)); 
}
